// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && title == "" {
				title = strings.TrimSpace(extractText(n))
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						if attr.Val == "description" {
							name = "description"
						}
					case "property":
						if attr.Val == "og:description" {
							name = "og:description"
						}
					case "content":
						content = attr.Val
					}
				}
				if name != "" && content != "" && description == "" {
					description = content
				}
			}
		}

		// Continue traversing unless we have both values
		if title == "" || description == "" {
			for c := n.FirstChild; c != nil; c = c.NextSibling {
				traverse(c)
			}
		}
	}

	traverse(doc)
	return title, description, nil
}

// extractText extracts all text content from an HTML node recursively.
func extractText(n *html.Node) string {
	if n.Type == html.TextNode {
		return n.Data
	}
	var result strings.Builder
	for c := n.FirstChild; c != nil; c = c.NextSibling {
		result.WriteString(extractText(c))
	}
	return result.String()
}

