	URL string `json:"url"`
}

type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	// Parse JSON body
	var req PreviewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		resp := PreviewResponse{Error: "Invalid JSON: " + err.Error()}
		data, _ := json.Marshal(resp)
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.Write(data)
		return
	}

	if req.URL == "" {
		resp := PreviewResponse{Error: "URL is required"}
		data, _ := json.Marshal(resp)
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		ctx.Write(data)
		return
	}

	// Create client with DialDualStack and 3 second timeout
	client := &fasthttp.Client{
		Dial:        fasthttp.DialDualStack,
		ReadTimeout: 3 * time.Second,
	}

	// Acquire request and response
	fastReq := fasthttp.AcquireRequest()
	fastResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(fastReq)
	defer fasthttp.ReleaseResponse(fastResp)

	fastReq.SetRequestURI(req.URL)
	fastReq.Header.SetMethod(fasthttp.MethodGet)
	fastReq.Header.Set("User-Agent", "URLPreview/1.0")

	// Use DoRedirects with max 10 redirects
	if err := client.DoRedirects(fastReq, fastResp, 10); err != nil {
		resp := PreviewResponse{Error: "Failed to fetch URL: " + err.Error()}
		data, _ := json.Marshal(resp)
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.Write(data)
		return
	}

	// Parse HTML
	title, description := extractMetaInfo(fastResp.Body())

	response := PreviewResponse{
		Title:       title,
		Description: description,
	}

	data, err := json.Marshal(response)
	if err != nil {
		resp := PreviewResponse{Error: "Internal error"}
		data, _ := json.Marshal(resp)
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.Write(data)
		return
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	ctx.Write(data)
}

func extractMetaInfo(body []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil && title == "" {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name", "property":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				nameLower := strings.ToLower(name)
				if (nameLower == "description" || nameLower == "og:description") && description == "" {
					description = strings.TrimSpace(content)
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)
	return title, description
}

func main() {
	server := &fasthttp.Server{
		Handler: func(ctx *fasthttp.RequestCtx) {
			switch string(ctx.Path()) {
			case "/preview":
