// isPrivateIP checks if the IP is private, loopback, link-local, or otherwise reserved.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// IPv4 specific checks
	if ip4 := ip.To4(); ip4 != nil {
		// 0.0.0.0/8
		if ip4[0] == 0 {
			return true
		}
		// 127.0.0.0/8 (loopback)
		if ip4[0] == 127 {
			return true
		}
		// 10.0.0.0/8
		if ip4[0] == 10 {
			return true
		}
		// 172.16.0.0/12
		if ip4[0] == 172 && ip4[1] >= 16 && ip4[1] <= 31 {
			return true
		}
		// 192.168.0.0/16
		if ip4[0] == 192 && ip4[1] == 168 {
			return true
		}
		// 169.254.0.0/16 (link-local)
		if ip4[0] == 169 && ip4[1] == 254 {
			return true
		}
	} else {
		// IPv6 checks
		// fc00::/7 (unique local)
		if len(ip) >= 1 && (ip[0]&0xfe) == 0xfc {
			return true
		}
		// fe80::/10 (link-local)
		if len(ip) >= 1 && (ip[0]&0xc0) == 0x80 {
			return true
		}
	}

	return false
}

// isBlockedHost checks if the host is localhost or resolves to a private IP.
func isBlockedHost(host string) bool {
	// Remove port if present
	if h, _, err := net.SplitHostPort(host); err == nil {
		host = h
	}

	host = strings.ToLower(strings.TrimSpace(host))

	// Check for localhost variants
	if host == "localhost" || host == "localhost.localdomain" || 
	   strings.HasSuffix(host, ".localhost") || host == "127.0.0.1" ||
	   host == "::1" || host == "0.0.0.0" || host == "0000:0000:0000:0000:0000:0000:0000:0001" ||
	   host == "0:0:0:0:0:0:0:1" {
		return true
	}

	// Check if it's an IP address
	if ip := net.ParseIP(host); ip != nil {
		return isPrivateIP(ip)
	}

	// Resolve hostname and check if any IP is private
	// This prevents DNS rebinding attacks to internal addresses
	ips, err := net.LookupIP(host)
	if err != nil {
		// If DNS lookup fails, we allow it to proceed (connection will likely fail)
		return false
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return true
		}
	}

	return false
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL scheme
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
		return
	}

	// SSRF Protection: Block internal/private addresses
	host := parsedURL.Hostname()
	if isBlockedHost(host) {
		ctx.Error("Access to internal addresses is not allowed", fasthttp.StatusForbidden)
		return
	}

	// Use fasthttp.Client to fetch with timeout
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirectCounts := 10
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Limit body size to prevent memory issues (e.g., 1MB)
	const maxBodySize = 1 * 1024 * 1024
	bodyBytes := res.Body()
	if len(bodyBytes) > maxBodySize {
		bodyBytes = bodyBytes[:maxBodySize]
	}

	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	// Copy body to avoid potential issues with buffer reuse
	bodyCopy := make([]byte, len(bodyBytes))
	copy(bodyCopy, bodyBytes)

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyCopy))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				var isOGDescription bool

				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "property":
						if attr.Val == "og:description" {
							isOGDescription = true
						}
					case "content":
						content = attr.Val
					}
				}

				if content != "" {
					if name == "description" {
						description = strings.TrimSpace(content)
					} else if isOGDescription && description == "" {
						description = strings.TrimSpace(content)
					}
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description, nil
}

