package main

import (
	"bytes"
	"encoding/json"
	"errors"
	"io"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

const (
	maxRequestBodySize  = 1 << 20 // 1MB
	maxResponseBodySize = 5 << 20 // 5MB
	requestTimeout      = 10 * time.Second
	maxRedirects        = 3
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	if !ctx.IsPost() {
		ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if len(body) == 0 {
		ctx.Error("Empty request body", fasthttp.StatusBadRequest)
		return
	}

	if len(body) > maxRequestBodySize {
		ctx.Error("Request body too large", fasthttp.StatusBadRequest)
		return
	}

	if err := json.Unmarshal(body, &req); err != nil {
		ctx.Error("Invalid JSON", fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		ctx.Error("URL is required", fasthttp.StatusBadRequest)
		return
	}

	// Parse and validate URL
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	// Security checks
	if err := validateURL(parsedURL); err != nil {
		ctx.Error(err.Error(), fasthttp.StatusBadRequest)
		return
	}

	// Create SSRF-safe client
	client := createSafeClient()

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(parsedURL.String())
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	// Do request with timeout and redirect limit
	if err := client.DoRedirects(freq, res, maxRedirects); err != nil {
		// Don't leak internal error details to client
		ctx.Error("Failed to fetch URL", fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error("Unexpected status code from target", fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	if len(bodyBytes) > maxResponseBodySize {
		ctx.Error("Response too large", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error("Failed to parse HTML", fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// validateURL checks URL for security issues (SSRF prevention)
func validateURL(u *url.URL) error {
	if u.Scheme != "http" && u.Scheme != "https" {
		return errors.New("URL must use http or https scheme")
	}

	// Reject URLs with credentials (user:pass@host)
	if u.User != nil {
		return errors.New("URL must not contain credentials")
	}

	hostname := u.Hostname()
	if hostname == "" {
		return errors.New("URL must have a hostname")
	}

	// Check for localhost variations
	if isLocalhost(hostname) {
		return errors.New("URL not allowed")
	}

	// Check if hostname is a private IP address
	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateIP(ip) {
			return errors.New("URL not allowed")
		}
	}

	// Block internal/suspicious domains
	lowerHost := strings.ToLower(hostname)
	if strings.HasSuffix(lowerHost, ".local") || 
	   strings.HasSuffix(lowerHost, ".internal") ||
	   strings.HasSuffix(lowerHost, ".localhost") {
		return errors.New("URL not allowed")
	}

	return nil
}

func isLocalhost(host string) bool {
	lower := strings.ToLower(host)
	return lower == "localhost" || 
		   lower == "127.0.0.1" || 
		   lower == "::1" || 
		   lower == "0:0:0:0:0:0:0:1"
}

func isPrivateIP(ip net.IP) bool {
	// RFC 1918 and other private/special ranges
	privateRanges := []string{
		"10.0.0.0/8",     // Private
		"172.16.0.0/12",  // Private
		"192.168.0.0/16", // Private
		"127.0.0.0/8",    // Loopback
		"169.254.0.0/16", // Link-local
		"0.0.0.0/8",      // Current network
		"::1/128",        // IPv6 Loopback
		"fc00::/7",       // IPv6 Unique Local
		"fe80::/10",      // IPv6 Link-local
	}

	for _, cidr := range privateRanges {
		_, ipNet, err := net.ParseCIDR(cidr)
		if err != nil {
			continue
		}
		if ipNet.Contains(ip) {
			return true
		}
	}
	return false
}

// createSafeClient creates an HTTP client with SSRF protection
func createSafeClient() *fasthttp.Client {
	return &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			return ssrfSafeDial(addr)
		},
		ReadTimeout:         requestTimeout,
		WriteTimeout:        requestTimeout,
		MaxIdleConnDuration: requestTimeout,
		MaxConnsPerHost:     5,
	}
}

// ssrfSafeDial prevents connections to private IPs (DNS rebinding protection)
func ssrfSafeDial(addr string) (net.Conn, error) {
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Resolve hostname to IPs
	ips, err := net.LookupIP(host)
	if err != nil {
		return nil, err
	}

	// Try connecting to first non-private IP
	var lastErr error
	for _, ip := range ips {
		if isPrivateIP(ip) {
			continue
		}

		dialer := &net.Dialer{
			Timeout: 5 * time.Second,
		}
		conn, err := dialer.Dial("tcp", net.JoinHostPort(ip.String(), port))
		if err == nil {
			return conn, nil
		}
		lastErr = err
	}

	if lastErr != nil {
		return nil, lastErr
	}
	return nil, errors.New("no valid IP address found")
}

// parseHTMLPreview extracts title and meta description from HTML
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	// Limit reading to prevent memory exhaustion
	limitedReader := io.LimitReader(r, maxResponseBodySize)
	doc, err := html.Parse(limitedReader)
	if err != nil {
		return "", "", err
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil && title == "" {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				var name, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if strings.ToLower(name) == "description" && description == "" {
					description = strings.TrimSpace(content)
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)

	// Truncate long strings to prevent DoS
	const maxLen = 1000
	if len(title) > maxLen {
		title = title[:maxLen]
	}
	if len(description) > maxLen {
		description = description[:maxLen]
	}

	return title, description, nil
}

