// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil && title == "" {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract meta description (check both standard and Open Graph)
			if n.Data == "meta" {
				var content string
				isDescription := false

				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.EqualFold(attr.Val, "description") {
						isDescription = true
					}
					if attr.Key == "property" && strings.EqualFold(attr.Val, "og:description") {
						isDescription = true
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}

				if isDescription && content != "" && description == "" {
					description = strings.TrimSpace(content)
				}
			}
		}

		// Traverse children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description, nil
}

