func fetchWithRedirectValidation(client *fasthttp.Client, targetURL string, maxBodySize int, maxRedirects int) ([]byte, int, error) {
	currentURL := targetURL
	redirectCount := 0

	for {
		parsedURL, err := url.Parse(currentURL)
		if err != nil {
			return nil, 0, fmt.Errorf("invalid URL: %w", err)
		}

		// Validate SSRF on every request (including redirects)
		if isPrivateHost(parsedURL.Hostname()) {
			return nil, 0, fmt.Errorf("redirect to private network detected")
		}

		freq := fasthttp.AcquireRequest()
		res := fasthttp.AcquireResponse()

		freq.SetRequestURI(currentURL)
		freq.Header.SetMethod("GET")
		freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
		freq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

		err = client.Do(freq, res)

		// Release request immediately
		fasthttp.ReleaseRequest(freq)

		if err != nil {
			fasthttp.ReleaseResponse(res)
			return nil, 0, err
		}

		statusCode := res.StatusCode()

		// Handle redirects manually
		if statusCode >= 300 && statusCode < 400 {
			location := string(res.Header.Peek("Location"))
			fasthttp.ReleaseResponse(res)

			if location == "" {
				return nil, statusCode, fmt.Errorf("redirect without location header")
			}

			// Resolve relative URLs
			if strings.HasPrefix(location, "http://") || strings.HasPrefix(location, "https://") {
				currentURL = location
			} else {
				// Handle relative URLs
				base, err := url.Parse(currentURL)
				if err != nil {
					return nil, 0, fmt.Errorf("failed to parse base URL: %w", err)
				}
				loc, err := url.Parse(location)
				if err != nil {
					return nil, 0, fmt.Errorf("failed to parse location: %w", err)
				}
				currentURL = base.ResolveReference(loc).String()
			}

			redirectCount++
			if redirectCount > maxRedirects {
				return nil, 0, fmt.Errorf("too many redirects")
			}
			continue
		}

		// Not a redirect, process body
		bodyBytes := res.Body()

		// Limit body size to prevent memory exhaustion
		if len(bodyBytes) > maxBodySize {
			fasthttp.ReleaseResponse(res)
			return nil, statusCode, fmt.Errorf("response body too large")
		}

		// Copy bytes since res will be released
		result := make([]byte, len(bodyBytes))
		copy(result, bodyBytes)

		fasthttp.ReleaseResponse(res)
		return result, statusCode, nil
	}
}

// createSecureDialer creates a dial function that blocks private IP addresses
// to prevent SSRF attacks at the network level.
func createSecureDialer() func(addr string) (net.Conn, error) {
	return func(addr string) (net.Conn, error) {
		host, _, err := net.SplitHostPort(addr)
		if err != nil {
			// If no port, use the whole addr as host
			host = addr
		}

		// Check if host is already an IP address
		ip := net.ParseIP(host)
		if ip != nil {
			if isPrivateIP(ip) {
				return nil, fmt.Errorf("connection to private IP blocked")
			}
			return fasthttp.DialDualStack(addr)
		}

		// For hostnames, resolve and check all IPs
		ips, err := net.LookupIP(host)
		if err != nil {
			return nil, fmt.Errorf("DNS lookup failed: %w", err)
		}

		if len(ips) == 0 {
			return nil, fmt.Errorf("no IP addresses found for host")
		}

		// Check if any resolved IP is private
		for _, ip := range ips {
			if isPrivateIP(ip) {
				return nil, fmt.Errorf("connection to private IP blocked")
			}
		}

		// Proceed with connection using dual stack
		return fasthttp.DialDualStack(addr)
	}
}

// isPrivateHost checks if the hostname resolves to a private/internal IP address.
// This is used for application-level SSRF protection.
func isPrivateHost(hostname string) bool {
	hostname = strings.ToLower(strings.TrimSpace(hostname))

	// Check for localhost names
	if hostname == "localhost" || hostname == "127.0.0.1" || hostname == "::1" || hostname == "0.0.0.0" {
		return true
	}

	// Check if it's an IP address
	ip := net.ParseIP(hostname)
	if ip != nil {
		return isPrivateIP(ip)
	}

	// For hostnames, check if it resolves to any private IP
	ips, err := net.LookupIP(hostname)
	if err != nil {
		// If we can't resolve, block it to be safe (fail closed)
		return true
	}

	for _, ip := range ips {
		if isPrivateIP(ip) {
			return true
		}
	}

	return false
}

// isPrivateIP checks if an IP address is private, loopback, or link-local.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() {
		return true
	}
	if ip.IsPrivate() {
		return true
	}
	// Check link-local addresses (169.254.0.0/16 and fe80::/10)
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	return false
}

