	result := map[string]string{
		"title":       title,
		"description": description,
	}
	if err := json.NewEncoder(ctx).Encode(result); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.Write([]byte(`{"error":"failed to encode response"}`))
	}
}

func extractPreviewData(body []byte) (title, description string) {
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		// Early exit if we have both values
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil && title == "" {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, property, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = attr.Val
					case "property":
						property = attr.Val
					case "content":
						content = attr.Val
					}
				}

				if description == "" {
					if name == "description" {
						description = content
					} else if property == "og:description" {
						description = content
					}
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return
}

func main() {
	server := &fasthttp.Server{
