package main

import (
	"bytes"
	"encoding/json"
	"fmt"
	"io"
	"net"
	"net/url"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

// PreviewResponse represents the JSON response structure.
type PreviewResponse struct {
	Title       string `json:"title,omitempty"`
	Description string `json:"description,omitempty"`
	Error       string `json:"error,omitempty"`
}

// isPrivateIP checks if the IP address is private, loopback, or link-local
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsPrivate() {
		return true
	}

	// Check for zero/unspecified address
	if ip.Equal(net.IPv4zero) || ip.Equal(net.IPv6zero) {
		return true
	}

	return false
}

// validateURL checks if the URL is safe to fetch (SSRF protection)
func validateURL(targetURL string) error {
	parsedURL, err := url.ParseRequestURI(targetURL)
	if err != nil {
		return fmt.Errorf("invalid URL format")
	}

	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("URL must use http or https scheme")
	}

	hostname := parsedURL.Hostname()

	// Check if hostname is an IP address
	if ip := net.ParseIP(hostname); ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to internal addresses is not allowed")
		}
		return nil
	}

	// Resolve hostname to IP addresses
	ips, err := net.LookupIP(hostname)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname")
	}

	// Check if any resolved IP is private
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to internal addresses is not allowed")
		}
	}

	return nil
}

// FetchURLPreview handles POST requests to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Only allow POST
	if !ctx.IsPost() {
		sendJSONResponse(ctx, PreviewResponse{Error: "Method not allowed"}, fasthttp.StatusMethodNotAllowed)
		return
	}

	var req struct {
		URL string `json:"url"`
	}

	body := ctx.PostBody()
	if err := json.Unmarshal(body, &req); err != nil {
		sendJSONResponse(ctx, PreviewResponse{Error: "Invalid JSON"}, fasthttp.StatusBadRequest)
		return
	}

	targetURL := strings.TrimSpace(req.URL)
	if targetURL == "" {
		sendJSONResponse(ctx, PreviewResponse{Error: "URL is required"}, fasthttp.StatusBadRequest)
		return
	}

	// Validate URL and check for SSRF
	if err := validateURL(targetURL); err != nil {
		sendJSONResponse(ctx, PreviewResponse{Error: err.Error()}, fasthttp.StatusBadRequest)
		return
	}

	// Use fasthttp.Client to fetch with timeout
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.SetRequestURI(targetURL)
	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirectCounts := 10
	if err := client.DoRedirects(freq, res, maxRedirectCounts); err != nil {
		sendJSONResponse(ctx, PreviewResponse{Error: fmt.Sprintf("Failed to fetch URL: %v", err)}, fasthttp.StatusBadGateway)
		return
	}

	if res.StatusCode() != fasthttp.StatusOK {
		sendJSONResponse(ctx, PreviewResponse{Error: fmt.Sprintf("Unexpected status code: %d", res.StatusCode())}, fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		sendJSONResponse(ctx, PreviewResponse{Error: "Empty response body"}, fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		sendJSONResponse(ctx, PreviewResponse{Error: fmt.Sprintf("Failed to parse HTML: %v", err)}, fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	sendJSONResponse(ctx, resp, fasthttp.StatusOK)
}

// sendJSONResponse sends a JSON response with the given status code.
func sendJSONResponse(ctx *fasthttp.RequestCtx, resp PreviewResponse, statusCode int) {
	ctx.SetStatusCode(statusCode)
	ctx.SetContentType("application/json; charset=utf-8")
	json.NewEncoder(ctx).Encode(resp)
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
