// parseHTMLPreview extracts title and meta description from HTML safely.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	// Limit reading to prevent memory exhaustion
	limitedReader := io.LimitReader(r, maxBodySize)
	data, err := io.ReadAll(limitedReader)
	if err != nil {
		return "", "", err
	}

	content := string(data)

	// Extract title - simple string search to avoid regex DoS
	if start := strings.Index(strings.ToLower(content), "<title>"); start != -1 {
		start += 7
		if end := strings.Index(strings.ToLower(content[start:]), "</title>"); end != -1 {
			title = strings.TrimSpace(content[start : start+end])
			// Sanitize and limit length
			title = strings.ReplaceAll(title, "\n", " ")
			title = strings.ReplaceAll(title, "\r", "")
			if len(title) > maxTitleLen {
				title = title[:maxTitleLen]
			}
		}
	}

	// Extract meta description
	contentLower := strings.ToLower(content)
	descIdx := strings.Index(contentLower, `name="description"`)
	if descIdx == -1 {
		descIdx = strings.Index(contentLower, `name='description'`)
	}
	if descIdx == -1 {
		descIdx = strings.Index(contentLower, "name=description")
	}

	if descIdx != -1 {
		// Look for content attribute after the name tag
		searchStart := descIdx
		searchEnd := descIdx + 500 // Limit search window
		if searchEnd > len(content) {
			searchEnd = len(content)
		}

		contentAttr := `content="`
		contentStart := strings.Index(contentLower[searchStart:searchEnd], contentAttr)
		if contentStart != -1 {
			contentStart += searchStart + len(contentAttr)
			if contentEnd := strings.Index(content[contentStart:], `"`); contentEnd != -1 {
				description = strings.TrimSpace(content[contentStart : contentStart+contentEnd])
				// Sanitize and limit length
				description = strings.ReplaceAll(description, "\n", " ")
				description = strings.ReplaceAll(description, "\r", "")
				if len(description) > maxDescLen {
					description = description[:maxDescLen]
				}
			}
		}
	}

	return title, description, nil
}

