	client := createSecureClient()

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")
	freq.Header.Set("Accept", "text/html,application/xhtml+xml,application/xml;q=0.9,*/*;q=0.8")

	currentURL := targetURL
	redirectCount := 0

	// Manual redirect handling to validate each URL against SSRF
	for {
		if redirectCount > maxRedirects {
			ctx.Error("Too many redirects", fasthttp.StatusBadRequest)
			return
		}

		parsedCurrent, err := url.Parse(currentURL)
		if err != nil {
			ctx.Error("Invalid URL", fasthttp.StatusBadRequest)
			return
		}

		// Check for private/internal hosts before each request
		if isPrivateHost(parsedCurrent.Hostname()) {
			ctx.Error("Invalid URL", fasthttp.StatusBadRequest)
			return
		}

		freq.SetRequestURI(currentURL)
		res.Reset()

		if err := client.Do(freq, res); err != nil {
			ctx.Error("Failed to fetch URL", fasthttp.StatusBadGateway)
			return
		}

		statusCode := res.StatusCode()
		if isRedirect(statusCode) {
			redirectCount++
			if redirectCount > maxRedirects {
				ctx.Error("Too many redirects", fasthttp.StatusBadRequest)
				return
			}

			location := string(res.Header.Peek("Location"))
			if location == "" {
				ctx.Error("Invalid redirect", fasthttp.StatusBadGateway)
				return
			}

			redirectURL, err := url.Parse(location)
			if err != nil {
				ctx.Error("Invalid redirect URL", fasthttp.StatusBadGateway)
				return
			}

			// Resolve relative URLs
			if !redirectURL.IsAbs() {
				redirectURL = parsedCurrent.ResolveReference(redirectURL)
			}

			// Validate redirect URL scheme
			if redirectURL.Scheme != "http" && redirectURL.Scheme != "https" {
				ctx.Error("Invalid URL", fasthttp.StatusBadRequest)
				return
			}

			// Check redirect target for private hosts
			if isPrivateHost(redirectURL.Hostname()) {
				ctx.Error("Invalid URL", fasthttp.StatusBadRequest)
				return
			}

			currentURL = redirectURL.String()
			continue
		}

		break
	}

	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error("Failed to fetch URL", fasthttp.StatusBadGateway)
		return
	}

	// Prevent memory exhaustion by checking content length
	contentLength := res.Header.ContentLength()
	if contentLength > maxResponseSize {
		ctx.Error("Response too large", fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	// Truncate if somehow larger than limit (e.g., chunked encoding)
	if len(bodyBytes) > maxResponseSize {
		bodyBytes = bodyBytes[:maxResponseSize]
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error("Failed to parse content", fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

func isRedirect(statusCode int) bool {
	return statusCode == fasthttp.StatusMovedPermanently ||
		statusCode == fasthttp.StatusFound ||
		statusCode == fasthttp.StatusSeeOther ||
		statusCode == fasthttp.StatusTemporaryRedirect ||
		statusCode == fasthttp.StatusPermanentRedirect
}

// createSecureClient creates an HTTP client that prevents SSRF by blocking private IP ranges
func createSecureClient() *fasthttp.Client {
	return &fasthttp.Client{
		Dial: func(addr string) (net.Conn, error) {
			host, port, err := net.SplitHostPort(addr)
			if err != nil {
				return nil, err
			}

			// Resolve hostname to IPs
			ips, err := net.LookupIP(host)
			if err != nil {
				return nil, err
			}

			dialer := &net.Dialer{
				Timeout:   requestTimeout,
				KeepAlive: 10 * time.Second,
			}

			// Try to connect only to non-private IPs
			var lastErr error
			for _, ip := range ips {
				if isPrivateIP(ip) {
					continue
				}

				ipStr := ip.String()
				if ip.To4() == nil {
					ipStr = "[" + ipStr + "]"
				}

				conn, err := dialer.Dial("tcp", net.JoinHostPort(ipStr, port))
				if err == nil {
					return conn, nil
				}
				lastErr = err
			}

			if lastErr != nil {
				return nil, lastErr
			}
			return nil, fmt.Errorf("no valid IP addresses")
		},
		ReadTimeout:         requestTimeout,
		WriteTimeout:        requestTimeout,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}
}

// isPrivateHost checks if the host is localhost or a private IP
func isPrivateHost(host string) bool {
	if host == "" {
		return false
	}

	lowerHost := strings.ToLower(host)
	if lowerHost == "localhost" || lowerHost == "127.0.0.1" || lowerHost == "::1" || lowerHost == "0.0.0.0" {
		return true
	}

	if ip := net.ParseIP(host); ip != nil {
		return isPrivateIP(ip)
	}

	return false
}

// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(ip net.IP) bool {
	if ip == nil {
		return false
	}

	// Check loopback, private, and link-local addresses
	if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for 0.0.0.0/8
	if ip4 := ip.To4(); ip4 != nil && ip4[0] == 0 {
		return true
	}

	return false
}

// parseHTMLPreview extracts title and meta description from HTML
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if title != "" && description != "" {
			return
		}

		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				if title == "" && n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				if description == "" {
					var name, content string
					for _, attr := range n.Attr {
						key := strings.ToLower(attr.Key)
						val := strings.ToLower(attr.Val)
						if key == "name" && val == "description" {
							name = attr.Val
						}
						if key == "content" {
							content = attr.Val
						}
					}
					if name != "" && content != "" {
						description = strings.TrimSpace(content)
					}
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description, nil
}

