// isLocalhost checks if hostname is localhost or loopback
func isLocalhost(hostname string) bool {
	lower := strings.ToLower(hostname)
	if lower == "localhost" || lower == "127.0.0.1" || lower == "::1" || lower == "[::1]" {
		return true
	}
	return false
}

// secureDial creates a connection with SSRF protection
func secureDial(addr string) (net.Conn, error) {
	// Parse address to get host and port
	host, port, err := net.SplitHostPort(addr)
	if err != nil {
		return nil, err
	}

	// Check if it's an IP address
	ip := net.ParseIP(host)
	if ip == nil {
		// It's a hostname, resolve it
		ips, err := net.LookupIP(host)
		if err != nil {
			return nil, err
		}
		if len(ips) == 0 {
			return nil, errors.New("no IP addresses found")
		}

		// Check all resolved IPs - if any is private, reject
		// This prevents DNS rebinding attacks where initial resolution is public
		// but subsequent is private
		for _, resolvedIP := range ips {
			if isPrivateIP(resolvedIP) {
				return nil, errors.New("connection to private IP ranges is not allowed")
			}
		}

		// Use the first public IP
		ip = ips[0]
	} else {
		// It's already an IP address, check it directly
		if isPrivateIP(ip) {
			return nil, errors.New("connection to private IP ranges is not allowed")
		}
	}

	// Dial the validated address
	dialer := &net.Dialer{
		Timeout: 10 * time.Second,
	}
	return dialer.Dial("tcp", net.JoinHostPort(ip.String(), port))
}

// isPrivateIP checks if an IP address is private, loopback, or reserved
func isPrivateIP(ip net.IP) bool {
	// Check for loopback
	if ip.IsLoopback() {
		return true
	}

	// Check for private ranges
	if ip.IsPrivate() {
		return true
	}

	// Check for link-local
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for multicast
	if ip.IsMulticast() {
		return true
	}

	// Check for unspecified
	if ip.IsUnspecified() {
		return true
	}

	// Check for IPv4 specific ranges that might not be covered
	if ip4 := ip.To4(); ip4 != nil {
		// 0.0.0.0/8
		if ip4[0] == 0 {
			return true
		}
		// 169.254.0.0/16 (link-local, already checked but double check)
		if ip4[0] == 169 && ip4[1] == 254 {
			return true
		}
		// 192.0.0.0/24 (IETF Protocol Assignments)
		if ip4[0] == 192 && ip4[1] == 0 && ip4[2] == 0 {
			return true
		}
		// 192.0.2.0/24 (TEST-NET-1)
