// isPrivateHost checks if the hostname is a private/internal host
func isPrivateHost(host string) bool {
	lowerHost := strings.ToLower(host)

	// Check for localhost variations
	localhostNames := []string{"localhost", "127.0.0.1", "::1", "0.0.0.0"}
	for _, name := range localhostNames {
		if lowerHost == name {
			return true
		}
	}

	// Check for common internal TLDs
	internalTLDs := []string{".local", ".internal", ".lan", ".private"}
	for _, tld := range internalTLDs {
		if strings.HasSuffix(lowerHost, tld) {
			return true
		}
	}

	// Check if it's a private IP directly
	if ip := net.ParseIP(host); ip != nil {
		return isPrivateIP(ip)
	}

	return false
}

// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(ip net.IP) bool {
	// Check for loopback, private ranges, link-local
	if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}

	// Check for CGNAT (Carrier-Grade NAT) range 100.64.0.0/10
	cgnat := net.IPNet{
		IP:   net.ParseIP("100.64.0.0"),
		Mask: net.CIDRMask(10, 32),
	}
	if cgnat.Contains(ip) {
		return true
	}

	return false
}

// isValidContentType checks if the content type is valid HTML
func isValidContentType(contentType string) bool {
	lower := strings.ToLower(contentType)
	return strings.Contains(lower, "text/html") || 
		   strings.Contains(lower, "application/xhtml+xml") ||
		   strings.Contains(lower, "application/html")
}

