package main

import (
	"encoding/json"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

var client = &fasthttp.Client{
	Dial:        fasthttp.DialDualStack,
	ReadTimeout: 3 * time.Second,
}

type requestBody struct {
	URL string `json:"url"`
}

type responseBody struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	// Parse JSON body
	var req requestBody
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(responseBody{Error: "invalid JSON: " + err.Error()})
		return
	}

	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(responseBody{Error: "url field is required"})
		return
	}

	// Fetch the URL
	title, desc, err := fetchURL(req.URL)
	if err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(responseBody{Error: "failed to fetch URL: " + err.Error()})
		return
	}

	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(responseBody{
		Title:       title,
		Description: desc,
	})
}

func fetchURL(url string) (string, string, error) {
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(url)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Use DoRedirects to fetch with redirect following (max 10 redirects)
	err := client.DoRedirects(req, resp, 10)
	if err != nil {
		return "", "", err
	}

	// Parse HTML content
	title, desc := extractMeta(string(resp.Body()))
	return title, desc, nil
}

func extractMeta(htmlContent string) (string, string) {
	doc, err := html.Parse(strings.NewReader(htmlContent))
	if err != nil {
		return "", ""
	}

	var title, description string
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			}

			// Extract meta description (check both standard and Open Graph)
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name", "property":
						name = attr.Val
					case "content":
						content = attr.Val
					}
				}
				if description == "" && (name == "description" || name == "og:description") {
					description = strings.TrimSpace(content)
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func main() {
	// Example server setup to demonstrate the handler
	server := &fasthttp.Server{
		Handler: func(ctx *fasthttp.RequestCtx) {
			switch string(ctx.Path()) {
			case "/preview":
				if ctx.IsPost() {
					FetchURLPreview(ctx)
				} else {
					ctx.Error("Method not allowed", fasthttp.StatusMethodNotAllowed)
				}
			default:
				ctx.Error("Not found", fasthttp.StatusNotFound)
			}
		},
	}

	if err := server.ListenAndServe(":8080"); err != nil {
		panic(err)
	}
}

