// isValidURL checks if the URL is valid and not an internal/private address (SSRF protection)
func isValidURL(rawURL string) error {
	parsedURL, err := url.Parse(rawURL)
	if err != nil {
		return fmt.Errorf("invalid URL")
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("only HTTP and HTTPS URLs are allowed")
	}

	// Check if host is empty
	if parsedURL.Host == "" {
		return fmt.Errorf("invalid URL: missing host")
	}

	// Extract hostname (without port)
	host, _, err := net.SplitHostPort(parsedURL.Host)
	if err != nil {
		// If SplitHostPort fails, assume it's just a hostname without port
		host = parsedURL.Host
	}

	// Check if it's an IP address
	ip := net.ParseIP(host)
	if ip != nil {
		// Check for private, loopback, link-local, multicast, etc.
		if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsMulticast() {
			return fmt.Errorf("access to internal addresses is not allowed")
		}
