// isValidURL checks if the URL is valid and not pointing to internal/private addresses (SSRF protection)
func isValidURL(rawURL string) bool {
	parsedURL, err := url.Parse(rawURL)
	if err != nil {
		return false
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return false
	}

	hostname := parsedURL.Hostname()
	if hostname == "" {
		return false
	}

	// Check if hostname is an IP address
	ip := net.ParseIP(hostname)
	if ip != nil {
		// Check for loopback, private, link-local, multicast, unspecified, etc.
		if ip.IsLoopback() || ip.IsPrivate() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() || ip.IsInterfaceLocalMulticast() || ip.IsUnspecified() {
			return false
		}
	}

	// Check for localhost and common internal names
	lowerHost := strings.ToLower(hostname)
	if lowerHost == "localhost" || strings.HasPrefix(lowerHost, "127.") || lowerHost == "::1" || lowerHost == "0.0.0.0" {
		return false
