		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		ctx.SetContentType("application/json")
		json.NewEncoder(ctx).Encode(PreviewResponse{Error: err.Error()})
		return
	}

	// Return successful response
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(PreviewResponse{
		Title:       title,
		Description: description,
	})
}

// fetchAndParseURL fetches the URL using DoRedirects and extracts title and meta description
func fetchAndParseURL(url string) (string, string, error) {
	req := fasthttp.AcquireRequest()
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(req)
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(url)
	req.Header.SetMethod(fasthttp.MethodGet)
	req.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreview/1.0)")

	// Use DoRedirects with a maximum of 10 redirects
	if err := client.DoRedirects(req, resp, 10); err != nil {
		return "", "", err
	}

	// Parse HTML content
	body := resp.Body()
	doc, err := html.Parse(bytes.NewReader(body))
	if err != nil {
		return "", "", err
	}

	var title, description string

	// Recursive function to traverse HTML nodes
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			switch n.Data {
			case "title":
				// Extract text content from title tag
				if n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			case "meta":
				// Check for meta description
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						name = attr.Val
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}
				if strings.EqualFold(name, "description") {
					description = strings.TrimSpace(content)
				}
			}
		}

		// Traverse children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description, nil
}

func main() {
	// Setup request handler
	requestHandler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}

	// Create and start server
	server := &fasthttp.Server{
		Handler: requestHandler,
	}

	// Listen on port 8080
	if err := server.ListenAndServe(":8080"); err != nil {
		panic(err)
	}
}

