)

// Request represents the JSON request body
type Request struct {
	URL string `json:"url"`
}

// Response represents the JSON response
type Response struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles the request to fetch URL preview
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	// Parse JSON body
	var req Request
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		resp := Response{Error: "Invalid JSON body"}
		sendJSON(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	if req.URL == "" {
		resp := Response{Error: "URL field is required"}
		sendJSON(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	// Create fasthttp client with DialDualStack
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
	}

	// Prepare request
	fastReq := fasthttp.AcquireRequest()
	fastResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(fastReq)
	defer fasthttp.ReleaseResponse(fastResp)

	fastReq.SetRequestURI(req.URL)
	fastReq.Header.SetMethod(fasthttp.MethodGet)
	fastReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreview/1.0)")

	// Execute request with timeout using DoRedirects
	done := make(chan error, 1)
	go func() {
		// Allow up to 10 redirects
		done <- client.DoRedirects(fastReq, fastResp, 10)
	}()

	select {
	case err := <-done:
		if err != nil {
			resp := Response{Error: "Failed to fetch URL: " + err.Error()}
			sendJSON(ctx, resp, fasthttp.StatusInternalServerError)
			return
		}
	case <-time.After(3 * time.Second):
		resp := Response{Error: "Request timeout"}
		sendJSON(ctx, resp, fasthttp.StatusRequestTimeout)
		return
	}

	// Parse HTML content
	body := fastResp.Body()
	title, description := extractMetadata(body)

	resp := Response{
		Title:       title,
		Description: description,
	}
	sendJSON(ctx, resp, fasthttp.StatusOK)
}

func sendJSON(ctx *fasthttp.RequestCtx, data interface{}, statusCode int) {
	ctx.SetStatusCode(statusCode)
	jsonData, _ := json.Marshal(data)
	ctx.Write(jsonData)
}

func extractMetadata(body []byte) (title, description string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil {
					title = strings.TrimSpace(n.FirstChild.Data)
				}
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content, property string
				for _, attr := range n.Attr {
					switch strings.ToLower(attr.Key) {
					case "name":
						name = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					case "property":
						property = strings.ToLower(attr.Val)
					}
				}

				if description == "" {
					if name == "description" && content != "" {
						description = content
					} else if property == "og:description" && content != "" {
						description = content
					}
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func main() {
	server := &fasthttp.Server{
		Handler: func(ctx *fasthttp.RequestCtx) {
			if string(ctx.Method()) == "POST" && string(ctx.Path()) == "/preview" {
				FetchURLPreview(ctx)
			} else {
				ctx.Error("Not Found", fasthttp.StatusNotFound)
			}
		},
	}

	if err := server.ListenAndServe(":8080"); err != nil {
		panic(err)
	}
}

