// Request represents the incoming JSON payload
type Request struct {
	URL string `json:"url"`
}

// Response represents the JSON response
type Response struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// Initialize fasthttp client with timeout
var client = &fasthttp.Client{
	Dial:         fasthttp.DialDualStack,
	ReadTimeout:  10 * time.Second,
	WriteTimeout: 10 * time.Second,
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	// Validate method
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		json.NewEncoder(ctx).Encode(Response{Error: "Method not allowed"})
		return
	}

	// Parse request body
	var req Request
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(Response{Error: "Invalid JSON body"})
		return
	}

	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(Response{Error: "URL field is required"})
		return
	}

	// SSRF Protection: Validate URL
	if err := validateURL(req.URL); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(Response{Error: fmt.Sprintf("Invalid URL: %v", err)})
		return
	}

	// Prepare request and response objects
	fastReq := fasthttp.AcquireRequest()
	fastResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(fastReq)
	defer fasthttp.ReleaseResponse(fastResp)

	fastReq.SetRequestURI(req.URL)
	fastReq.Header.SetMethod(fasthttp.MethodGet)
	fastReq.Header.Set("User-Agent", "Mozilla/5.0 (compatible; URLPreview/1.0)")

	// Execute request with max 10 redirects
	if err := client.DoRedirects(fastReq, fastResp, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		json.NewEncoder(ctx).Encode(Response{Error: fmt.Sprintf("Failed to fetch URL: %v", err)})
		return
	}

	// Parse HTML content
	body := fastResp.Body()
	title, description := extractMetaData(body)

	// Return success response
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(Response{
		Title:       title,
		Description: description,
	})
}

// validateURL checks for SSRF vulnerabilities by validating the URL
func validateURL(targetURL string) error {
	// Parse the URL
	parsedURL, err := url.Parse(targetURL)
	if err != nil {
		return fmt.Errorf("failed to parse URL")
	}

	// Check scheme
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("only http and https schemes are allowed")
	}

	// Get the hostname
	hostname := parsedURL.Hostname()
	if hostname == "" {
		return fmt.Errorf("invalid hostname")
	}

	// Check for localhost and common internal hostnames
	lowerHostname := strings.ToLower(hostname)
	if lowerHostname == "localhost" || lowerHostname == "127.0.0.1" || strings.HasPrefix(lowerHostname, "127.") {
		return fmt.Errorf("access to localhost is not allowed")
	}

	// Check for IPv6 localhost
	if hostname == "::1" || hostname == "[::1]" {
		return fmt.Errorf("access to localhost is not allowed")
	}

	// Resolve the hostname to IP addresses
	ips, err := net.LookupIP(hostname)
	if err != nil {
		// If we can't resolve, we should block it to be safe
		return fmt.Errorf("failed to resolve hostname")
	}

	// Check if any resolved IP is private/internal
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to internal addresses is not allowed")
		}
	}

	return nil
}

// isPrivateIP checks if an IP address is private/internal
func isPrivateIP(ip net.IP) bool {
	// Check for loopback
	if ip.IsLoopback() {
		return true
	}

	// Check for private ranges (RFC 1918)
	privateRanges := []string{
		"10.0.0.0/8",     // Private
		"172.16.0.0/12",  // Private
		"192.168.0.0/16", // Private
		"169.254.0.0/16", // Link-local
		"127.0.0.0/8",    // Loopback
		"0.0.0.0/8",      // Current network
		"100.64.0.0/10",  // Carrier-grade NAT
		"192.0.0.0/24",   // IETF Protocol Assignments
		"192.0.2.0/24",   // TEST-NET-1
		"198.18.0.0/15",  // Network benchmark tests
		"198.51.100.0/24",// TEST-NET-2
		"203.0.113.0/24", // TEST-NET-3
		"224.0.0.0/4",    // Multicast
		"240.0.0.0/4",    // Reserved
	}

	for _, cidr := range privateRanges {
		_, ipNet, err := net.ParseCIDR(cidr)
		if err != nil {
			continue
		}
		if ipNet.Contains(ip) {
			return true
		}
	}

	// Check for IPv6 private ranges
	if ip.To4() == nil {
		// IPv6
		if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
			return true
		}
		// fc00::/7 Unique local addresses
		uniqueLocal := net.IPNet{
			IP:   net.ParseIP("fc00::"),
			Mask: net.CIDRMask(7, 128),
		}
		if uniqueLocal.Contains(ip) {
			return true
		}
		// fe80::/10 Link-local addresses
		linkLocal := net.IPNet{
			IP:   net.ParseIP("fe80::"),
			Mask: net.CIDRMask(10, 128),
		}
		if linkLocal.Contains(ip) {
			return true
		}
	}

	return false
}

// extractMetaData parses HTML and extracts title and meta description
func extractMetaData(data []byte) (title, description string) {
	doc, err := html.Parse(bytes.NewReader(data))
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil && n.FirstChild.Type == html.TextNode {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name", "property":
						name = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					}
				}

				if (name == "description" || name == "og:description") && description == "" {
					description = strings.TrimSpace(content)
				}
			}
		}

		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

