import (
	"encoding/json"
	"fmt"
	"strings"
	"time"

	"github.com/valyala/fasthttp"
	"golang.org/x/net/html"
)

type previewRequest struct {
	URL string `json:"url"`
}

type previewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

var client = &fasthttp.Client{
	Dial: fasthttp.DialDualStack,
}

func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	ctx.SetContentType("application/json")

	var req previewRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		resp, _ := json.Marshal(previewResponse{Error: "Invalid JSON body"})
		ctx.Write(resp)
		return
	}

	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		resp, _ := json.Marshal(previewResponse{Error: "URL is required"})
		ctx.Write(resp)
		return
	}

	fastReq := fasthttp.AcquireRequest()
	fastResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(fastReq)
	defer fasthttp.ReleaseResponse(fastResp)

	fastReq.SetRequestURI(req.URL)
	fastReq.Header.SetMethod(fasthttp.MethodGet)
	fastReq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	timeout := 3 * time.Second
	if err := client.DoTimeout(fastReq, fastResp, timeout); err != nil {
		ctx.SetStatusCode(fasthttp.StatusInternalServerError)
		resp, _ := json.Marshal(previewResponse{Error: fmt.Sprintf("Failed to fetch URL: %v", err)})
		ctx.Write(resp)
		return
	}

	title, description := extractMetaInfo(fastResp.Body())

	ctx.SetStatusCode(fasthttp.StatusOK)
	resp, _ := json.Marshal(previewResponse{
		Title:       title,
		Description: description,
	})
	ctx.Write(resp)
}

func extractMetaInfo(body []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(body)))
	if err != nil {
		return "", ""
	}

	var title, description string
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && n.FirstChild != nil && title == "" {
				title = strings.TrimSpace(n.FirstChild.Data)
			}
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					if attr.Key == "name" {
						name = attr.Val
					} else if attr.Key == "content" {
						content = attr.Val
					}
				}
				if strings.EqualFold(name, "description") {
					description = content
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			if title != "" && description != "" {
				return
			}
			traverse(c)
		}
	}
	traverse(doc)
	return title, description
}

func main() {
	server := &fasthttp.Server{
		Handler: func(ctx *fasthttp.RequestCtx) {
			if string(ctx.Method()) == "POST" && string(ctx.Path()) == "/preview" {
				FetchURLPreview(ctx)
			} else {
				ctx.Error("Not found", fasthttp.StatusNotFound)
			}
		},
	}
	if err := server.ListenAndServe(":8080"); err != nil {
		panic(err)
	}
}

