// isPrivateIP checks if an IP address is private, loopback, link-local, or multicast
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() {
		return true
	}
	if ip.IsPrivate() {
		return true
	}
	if ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	if ip.IsMulticast() {
		return true
	}
	return false
}

// validateURL checks if a URL is safe to fetch (SSRF protection)
func validateURL(rawURL string) error {
	parsedURL, err := url.Parse(rawURL)
	if err != nil {
		return fmt.Errorf("invalid URL: %v", err)
	}

	// Only allow http and https schemes
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return fmt.Errorf("only http and https schemes are allowed")
	}

	host := parsedURL.Hostname()

	// Check for empty host
	if host == "" {
		return fmt.Errorf("invalid host")
	}

	// Check for localhost and loopback variants
	lowerHost := strings.ToLower(host)
	if lowerHost == "localhost" || lowerHost == "127.0.0.1" || lowerHost == "::1" || 
	   strings.HasPrefix(lowerHost, "127.") || lowerHost == "0.0.0.0" || lowerHost == "::" {
		return fmt.Errorf("access to localhost is not allowed")
	}

	// Check if host is a private IP address directly
	if ip := net.ParseIP(host); ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP addresses is not allowed")
		}
		return nil
	}

	// Resolve hostname to IPs
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname: %v", err)
	}

	if len(ips) == 0 {
		return fmt.Errorf("no IP addresses found for hostname")
	}

	// Check if any resolved IP is private
	for _, ip := range ips {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP addresses is not allowed")
		}
	}

	return nil
}

// Initialize fasthttp client with DialDualStack as required
var client = &fasthttp.Client{
	Dial: fasthttp.DialDualStack,
}

// Request structure for parsing incoming JSON
type urlRequest struct {
	URL string `json:"url"`
}

// Response structure for JSON output
type previewResponse struct {
	Title       string `json:"title"`
	Description string `json:"description"`
	Error       string `json:"error,omitempty"`
}

// FetchURLPreview handles POST requests to fetch and parse URL metadata
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// Set response content type
	ctx.SetContentType("application/json")

	// Validate HTTP method
	if !ctx.IsPost() {
		ctx.SetStatusCode(fasthttp.StatusMethodNotAllowed)
		json.NewEncoder(ctx).Encode(previewResponse{Error: "Only POST method is allowed"})
		return
	}

	// Parse request body
	var req urlRequest
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(previewResponse{Error: "Invalid JSON body: " + err.Error()})
		return
	}

	// Validate URL presence
	if req.URL == "" {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(previewResponse{Error: "url field is required"})
		return
	}

	// SSRF Protection: Validate URL before fetching to prevent access to internal resources
	if err := validateURL(req.URL); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(previewResponse{Error: "Invalid URL: " + err.Error()})
		return
	}

	// Acquire request and response objects from pool
	fastReq := fasthttp.AcquireRequest()
	fastResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(fastReq)
	defer fasthttp.ReleaseResponse(fastResp)

	// Configure request
	fastReq.SetRequestURI(req.URL)
	fastReq.Header.SetMethod(fasthttp.MethodGet)
	fastReq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	// Execute request with redirect following (max 10 redirects)
	if err := client.DoRedirects(fastReq, fastResp, 10); err != nil {
		ctx.SetStatusCode(fasthttp.StatusBadGateway)
		json.NewEncoder(ctx).Encode(previewResponse{Error: "Failed to fetch URL: " + err.Error()})
		return
	}

	// Check if content is HTML
	contentType := string(fastResp.Header.ContentType())
	if !strings.Contains(contentType, "text/html") {
		ctx.SetStatusCode(fasthttp.StatusBadRequest)
		json.NewEncoder(ctx).Encode(previewResponse{Error: "URL does not return HTML content"})
		return
	}

	// Parse HTML to extract title and meta description
	title, description := extractHTMLMeta(bytes.NewReader(fastResp.Body()))

	// Return successful response
	ctx.SetStatusCode(fasthttp.StatusOK)
	json.NewEncoder(ctx).Encode(previewResponse{
		Title:       title,
		Description: description,
	})
}

// extractHTMLMeta parses HTML content to extract title and meta description
func extractHTMLMeta(r io.Reader) (title, description string) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", ""
	}

	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract title
			if n.Data == "title" && n.FirstChild != nil {
				title = strings.TrimSpace(n.FirstChild.Data)
			}

			// Extract meta description
			if n.Data == "meta" {
				var name, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						if strings.EqualFold(attr.Val, "description") {
							name = attr.Val
						}
					case "content":
						content = attr.Val
					}
				}
				if name != "" && content != "" {
					description = strings.TrimSpace(content)
				}
			}
		}

		// Traverse child nodes
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}

	traverse(doc)
	return title, description
}

func main() {
	// Create server with the handler
	server := &fasthttp.Server{
		Handler: FetchURLPreview,
	}

	// Start listening on port 8080
	if err := server.ListenAndServe(":8080"); err != nil {
		panic(err)
	}
}

